using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;
using System.ComponentModel;
using System.Text.Json;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseFunctionInvocation()
    .Use(new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient()));

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();

// Tools
var notebook = new Notebook();
var tools = new object[] { new WebSearchTool(), notebook };

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = tools.SelectMany(t => AIFunctionFactory.Create(t)).ToList<AITool>(),
};

// Get topic from user
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

var systemPrompt = """
    You are a research agent. Your goal is to research the given topic thoroughly.

    Workflow:
    1. Search the web for information on the topic using multiple queries.
    2. Take notes on key findings using the note-taking tool.
    3. After gathering enough information (at least 3 searches), provide a 
       comprehensive summary of your findings.

    Always take notes before summarizing. Include your sources.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Research the following topic: {topic}"),
};

Console.WriteLine($"\nResearching: {topic}\n");
Console.WriteLine(new string('-', 60));

int iteration = 0;
const int maxIterations = 10;

while (iteration < maxIterations)
{
    iteration++;
    var response = await chatClient.GetResponseAsync(messages, chatOptions);

    // Append assistant response to history
    foreach (var msg in response.Messages)
    {
        messages.Add(msg);
    }

    // If no tool calls were made, the agent is done
    if (response.FinishReason == ChatFinishReason.Stop)
    {
        Console.WriteLine("\n" + new string('=', 60));
        Console.WriteLine("RESEARCH SUMMARY");
        Console.WriteLine(new string('=', 60));
        Console.WriteLine(response.Text);
        break;
    }
}

if (iteration >= maxIterations)
{
    Console.WriteLine("\n[Agent reached iteration limit]");
}

// Display collected notes
if (notebook.Notes.Count > 0)
{
    Console.WriteLine("\n" + new string('-', 60));
    Console.WriteLine($"NOTES COLLECTED ({notebook.Notes.Count}):");
    Console.WriteLine(new string('-', 60));
    foreach (var (i, note) in notebook.Notes.Select((n, i) => (i, n)))
    {
        Console.WriteLine($"  {i + 1}. {note}");
    }
}

// --- Tool Definitions ---

/// <summary>Simulates web search results for a query.</summary>
public sealed class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for information. Returns a list of search result snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Use DuckDuckGo instant answer API (no key required)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await Http.GetStringAsync(url, cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) && text.GetString() is string t && t.Length > 0)
                    {
                        var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                        results.Add($"[{firstUrl}] {t}");
                    }
                }
            }

            if (results.Count == 0)
            {
                results.Add($"No detailed results found for '{query}'. Try a more specific query.");
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>Tool for taking and retrieving research notes.</summary>
public sealed class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Save a research note. Use this to record key findings from search results.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note #{Notes.Count} saved");
        return $"Note saved (total notes: {Notes.Count}).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", Notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

