         var encoded = Uri.EscapeDataString(query);
         var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

         try
         {
             var json = await Http.GetStringAsync(url, cancellationToken);
             using var doc = JsonDocument.Parse(json);
             var root = doc.RootElement;

             var results = new List<string>();

             // Abstract
             var abstractText = root.GetProperty("Abstract").GetString();
             var abstractSource = root.GetProperty("AbstractSource").GetString();
             if (!string.IsNullOrEmpty(abstractText))
             {
                 results.Add($"[{abstractSource}] {abstractText}");
             }

             // Related topics
             if (root.TryGetProperty("RelatedTopics", out var related))
             {
                 foreach (var item in related.EnumerateArray().Take(5))
                 {
                     if (item.TryGetProperty("Text", out var text) && text.GetString() is string t && t.Length > 0)
                     {
                         var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                         results.Add($"[{firstUrl}] {t}");
                     }
                 }
             }

             if (results.Count == 0)
             {
                 results.Add($"No detailed results found for '{query}'. Try a more specific query.");
             }

             return string.Join("\n\n", results);
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }
 }

 /// <summary>Tool for taking and retrieving research notes.</summary>
 public sealed class Notebook
 {
     public List<string> Notes { get; } = [];

     [Description("Save a research note. Use this to record key findings from search results.")]
     public string TakeNote(
         [Description("The note content to save")] string note)
     {
         Notes.Add(note);
         Console.WriteLine($"  📝 Note #{Notes.Count} saved");
         return $"Note saved (total notes: {Notes.Count}).";
     }

     [Description("Retrieve all saved research notes.")]
     public string GetNotes()
     {
         if (Notes.Count == 0)
             return "No notes saved yet.";

         return string.Join("\n", Notes.Select((n, i) => $"{i + 1}. {n}"));
     }
 }
